#define OBSTACLES_NO 2
#define OBSTACLE_SPEED 5
#define FIGHTER_Y 140

void delay_ms(uint32_t ms)
{
    volatile uint32_t count;

    while(ms--)
    {
        count = 800;

        while(count--)
        {
            __NOP();
        }
    }
}

void error_handler(void)
{
    while(1)
    {
        LED1_GPIO->BSRR |= (1 << LED1_PIN);
        delay_ms(100);
        LED1_GPIO->BRR |= (1 << LED1_PIN);
        delay_ms(100);

        LED1_GPIO->BSRR |= (1 << LED1_PIN);
        delay_ms(100);
        LED1_GPIO->BRR |= (1 << LED1_PIN);
        delay_ms(100);
        
        LED1_GPIO->BSRR |= (1 << LED1_PIN);
        delay_ms(100);
        LED1_GPIO->BRR |= (1 << LED1_PIN);
        delay_ms(2000);
    }
}

QueueHandle_t xDisplayQueue;

EventGroupHandle_t xSystemFlags;

SemaphoreHandle_t g_accel_data_mutex;
SemaphoreHandle_t i2cFreeSemaphoreHandle;
SemaphoreHandle_t g_fighter_x_mutex;

LIS3DH_Data g_accel_data;
uint8_t g_fighter_x = 0;

